import{_ as a,o as t,c as i,ae as l}from"./chunks/framework.jfJLTIcL.js";const u=JSON.parse('{"title":"LAN Deployment","description":"","frontmatter":{},"headers":[],"relativePath":"en/lan-deployment.md","filePath":"en/lan-deployment.md","lastUpdated":1774613296000}'),n={name:"en/lan-deployment.md"};function o(s,e,r,h,d,c){return t(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="lan-deployment" tabindex="-1">LAN Deployment <a class="header-anchor" href="#lan-deployment" aria-label="Permalink to &quot;LAN Deployment&quot;">​</a></h1><h2 id="goal" tabindex="-1">Goal <a class="header-anchor" href="#goal" aria-label="Permalink to &quot;Goal&quot;">​</a></h2><p>Run VILab on one host machine and allow other machines on the same network to call its <code>/v1/*</code> endpoints.</p><h2 id="recommended-setup" tabindex="-1">Recommended setup <a class="header-anchor" href="#recommended-setup" aria-label="Permalink to &quot;Recommended setup&quot;">​</a></h2><ul><li>One machine runs the VILab desktop host</li><li>That machine manages providers and external API keys</li><li>Other internal apps use project-scoped external API keys</li></ul><h2 id="bind-the-service-to-the-network" tabindex="-1">Bind the service to the network <a class="header-anchor" href="#bind-the-service-to-the-network" aria-label="Permalink to &quot;Bind the service to the network&quot;">​</a></h2><p>The embedded service binds to the host and port configured in <strong>Server URL</strong>.</p><p>Recommended host-side value:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://0.0.0.0:8765</span></span></code></pre></div><p>Client-side callers should use the actual LAN IP or hostname of the host machine, for example:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://192.168.1.24:8765</span></span></code></pre></div><h2 id="firewall-and-reachability" tabindex="-1">Firewall and reachability <a class="header-anchor" href="#firewall-and-reachability" aria-label="Permalink to &quot;Firewall and reachability&quot;">​</a></h2><ul><li>Allow inbound TCP traffic on the service port</li><li>Confirm that clients on the same LAN can reach the host IP</li><li>Keep the service on trusted internal networks only</li></ul><h2 id="health-check-from-another-machine" tabindex="-1">Health check from another machine <a class="header-anchor" href="#health-check-from-another-machine" aria-label="Permalink to &quot;Health check from another machine&quot;">​</a></h2><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl http:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">192.168</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.24</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8765</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">health</span></span></code></pre></div><h2 id="authentication-model" tabindex="-1">Authentication model <a class="header-anchor" href="#authentication-model" aria-label="Permalink to &quot;Authentication model&quot;">​</a></h2><ul><li><code>/health</code> does not require an API key</li><li><code>/v1/*</code> requires <code>Authorization: Bearer &lt;external_api_key&gt;</code></li><li><code>/admin/*</code> requires <code>Authorization: Bearer &lt;adminKey&gt;</code></li></ul><p>The current implementation still accepts <code>adminKey</code> on public endpoints, but that is not the recommended operational model. Use external API keys for integrations.</p><h2 id="key-issuance-rule" tabindex="-1">Key issuance rule <a class="header-anchor" href="#key-issuance-rule" aria-label="Permalink to &quot;Key issuance rule&quot;">​</a></h2><p>Issue one external API key per:</p><ul><li>Project</li><li>Script</li><li>Device</li><li>Integration</li></ul><p>Recommended names:</p><ul><li><code>web-dashboard-prod</code></li><li><code>ios-prototype-lab</code></li><li><code>robot-gateway-01</code></li></ul><h2 id="operational-note" tabindex="-1">Operational note <a class="header-anchor" href="#operational-note" aria-label="Permalink to &quot;Operational note&quot;">​</a></h2><p>This first phase does not include:</p><ul><li>User accounts</li><li>Team login</li><li>Key scopes</li><li>Key expiry</li><li>Rate limits</li></ul><p>Those are follow-up hardening features, not requirements for self-hosted LAN use.</p>',27)])])}const m=a(n,[["render",o]]);export{u as __pageData,m as default};
